struct Rect { width: f64, height: f64 }

impl Rect {
    fn area(&self) -> f64 {
        self.width * self.height
    }
    fn perimeter(&self) -> f64 {
        2.0 * (self.width + self.height)
    }
}

fn main() {
    let r = Rect { width: 6.0, height: 4.0 };
    println!("area={} perimeter={}", r.area(), r.perimeter());
}

struct Stack {
    items: Vec<i32>,
}

impl Stack {
    fn push(&mut self, n: i32) {
        self.items.push(n);
    }
    fn pop(&mut self) -> Option<i32> {
        self.items.pop()
    }
    fn len(&self) -> usize {
        self.items.len()
    }
}

fn main() {
    let mut s = Stack { items: vec![] };
    s.push(1); s.push(2); s.push(3);
    println!("{:?}", s.pop());
    println!("len: {}", s.len());
}

struct Circle {
    radius: f64,
}

impl Circle {
    fn new(radius: f64) -> Circle {
        Circle { radius }
    }
    fn area(&self) -> f64 {
        std::f64::consts::PI * self.radius * self.radius
    }
}

fn main() {
    let c = Circle::new(5.0);
    println!("{:.4}", c.area());
}

