struct Metres(f64);
struct Kilograms(f64);

fn bmi(weight: Kilograms, height: Metres) -> f64 {
    weight.0 / (height.0 * height.0)
}

fn main() {
    let bmi = bmi(Kilograms(70.0), Metres(1.75));
    println!("{:.1}", bmi);
}
